1244	       * Extrudes a closed 2D `profileMm` along an open or closed
1245	       * `pathMm` polyline. Used for fascia, gutters, mullion bodies,
1246	       * picture-frame outlines around recessed loggias, and any
1247	       * linear architectural feature with a constant cross-section.
1248	       */
1249	      kind: 'sweep';
1250	      id: string;
1251	      name?: string;
1252	      levelId: string;
1253	      pathMm: { xMm: number; yMm: number; zMm?: number }[];
