import React, { useState } from 'react';

import type { Comment } from '@bim-ai/core';

import { CommentThread } from './CommentThread';

interface Props {
  comment: Comment;
  /** Projected 2D canvas position of the anchor. */
  x: number;
  y: number;
  modelId: string;
  allComments: Comment[];
}

export function CommentPin({ comment, x, y, modelId, allComments }: Props) {
  const [open, setOpen] = useState(false);

  const initials = comment.authorId.slice(0, 2).toUpperCase();
  const isResolved = comment.resolvedAt != null;
  const isOrphaned = comment.isOrphaned === true;

  const threadComments = allComments.filter((c) => c.threadId === comment.threadId);

  return (
    <>
      <g
        transform={`translate(${x},${y})`}
        style={{ cursor: 'pointer', opacity: isResolved ? 0.3 : 1 }}
        onClick={() => setOpen(true)}
        role="button"
        aria-label={`Comment by ${comment.authorId}`}
      >
        <circle r={14} fill="var(--cat-wall)" stroke="var(--surface-1)" strokeWidth={2} />
        {isOrphaned ? (
          <text
            textAnchor="middle"
            dominantBaseline="central"
            fontSize={14}
            fill="var(--semantic-warning)"
            fontWeight="bold"
          >
            ?
          </text>
        ) : (
          <text
            textAnchor="middle"
            dominantBaseline="central"
            fontSize={10}
            fill="var(--surface-1)"
            fontWeight="600"
          >
            {initials}
          </text>
        )}
      </g>

      {open && (
        <foreignObject x={x + 18} y={y - 20} width={320} height={400}>
          <CommentThread
            modelId={modelId}
            threadId={comment.threadId}
            comments={threadComments}
            onClose={() => setOpen(false)}
          />
        </foreignObject>
      )}
    </>
  );
}

