import React, { useEffect, useRef, useState } from 'react';

import type { Comment } from '@bim-ai/core';

import { useCommentStore } from './commentStore';

interface Props {
  modelId: string;
  threadId: string;
  comments: Comment[];
  onClose: () => void;
}

const MENTION_RE = /@(\w*)$/;

export function CommentThread({ modelId, threadId, comments, onClose }: Props) {
  const [body, setBody] = useState('');
  const [mentionQuery, setMentionQuery] = useState<string | null>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const { addComment, resolveComment } = useCommentStore();

  const rootComment = comments.find((c) => c.threadId === c.id) ?? comments[0];

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  function handleBodyChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
    const val = e.target.value;
    setBody(val);
    const match = MENTION_RE.exec(val);
    setMentionQuery(match ? match[1] ?? '' : null);
  }

  async function handleSubmit() {
    if (!body.trim() || !rootComment) return;
    await addComment(modelId, {
      threadId,
      authorId: 'local',
      body: body.trim(),
      anchor: rootComment.anchor,
    } as Omit<Comment, 'id' | 'modelId' | 'createdAt' | 'isOrphaned'>);
    setBody('');
  }

  async function handleResolve() {
    if (!rootComment) return;
    await resolveComment(modelId, rootComment.id);
    onClose();
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === 'Enter' && !e.shiftKey && !e.metaKey) {
      e.preventDefault();
      void handleSubmit();
    }
    if (e.key === 'Enter' && e.metaKey) {
      e.preventDefault();
      void handleResolve();
    }
    if (e.key === 'Escape') {
      onClose();
    }
  }

  const isResolved = rootComment?.resolvedAt != null;

  return (
    <div
      style={{
        background: 'var(--surface-1)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 8,
        padding: 12,
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
        animation: 'slideIn 200ms var(--ease-paper)',
        boxShadow: 'var(--shadow-popover)',
        maxHeight: 380,
        overflow: 'hidden',
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600 }}>
          Thread
        </span>
        <div style={{ display: 'flex', gap: 6 }}>
          {!isResolved && (
            <button
              onClick={() => void handleResolve()}
              style={{
                fontSize: 11,
