import React, { useEffect, useRef, useState } from 'react';

import type { Comment } from '@bim-ai/core';

import { useCommentStore } from './commentStore';

interface Props {
  modelId: string;
  threadId: string;
  comments: Comment[];
  onClose: () => void;
}

const MENTION_RE = /@(\w*)$/;

export function CommentThread({ modelId, threadId, comments, onClose }: Props) {
  const [body, setBody] = useState('');
  const [mentionQuery, setMentionQuery] = useState<string | null>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const { addComment, resolveComment } = useCommentStore();

  const rootComment = comments.find((c) => c.threadId === c.id) ?? comments[0];

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  function handleBodyChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
    const val = e.target.value;
    setBody(val);
    const match = MENTION_RE.exec(val);
    setMentionQuery(match ? match[1] ?? '' : null);
  }

  async function handleSubmit() {
    if (!body.trim() || !rootComment) return;
    await addComment(modelId, {
      threadId,
      authorId: 'local',
      body: body.trim(),
      anchor: rootComment.anchor,
    } as Omit<Comment, 'id' | 'modelId' | 'createdAt' | 'isOrphaned'>);
    setBody('');
  }

  async function handleResolve() {
    if (!rootComment) return;
    await resolveComment(modelId, rootComment.id);
    onClose();
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === 'Enter' && !e.shiftKey && !e.metaKey) {
      e.preventDefault();
      void handleSubmit();
    }
    if (e.key === 'Enter' && e.metaKey) {
      e.preventDefault();
      void handleResolve();
    }
    if (e.key === 'Escape') {
      onClose();
    }
  }

  const isResolved = rootComment?.resolvedAt != null;

  return (
    <div
      style={{
        background: 'var(--surface-1)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 8,
        padding: 12,
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
        animation: 'slideIn 200ms var(--ease-paper)',
        boxShadow: 'var(--shadow-popover)',
        maxHeight: 380,
        overflow: 'hidden',
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: 12, color: 'var(--text-muted)', fontWeight: 600 }}>
          Thread
        </span>
        <div style={{ display: 'flex', gap: 6 }}>
          {!isResolved && (
            <button
              onClick={() => void handleResolve()}
              style={{
                fontSize: 11,
                padding: '2px 8px',
                borderRadius: 4,
                border: '1px solid var(--border-subtle)',
                background: 'var(--surface-2)',
                color: 'var(--text-primary)',
                cursor: 'pointer',
              }}
            >
              Resolve
            </button>
          )}
          <button
            onClick={onClose}
            style={{
              fontSize: 14,
              lineHeight: 1,
              border: 'none',
              background: 'none',
              cursor: 'pointer',
              color: 'var(--text-muted)',
            }}
            aria-label="Close"
          >
            ×
          </button>
        </div>
      </div>

      <div style={{ overflowY: 'auto', flex: 1, display: 'flex', flexDirection: 'column', gap: 8 }}>
        {comments.map((c) => (
          <div key={c.id} style={{ fontSize: 13 }}>
            <span style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{c.authorId}</span>
            <span style={{ color: 'var(--text-muted)', marginLeft: 6, fontSize: 11 }}>
              {new Date(c.createdAt).toLocaleTimeString()}
            </span>
            <p style={{ margin: '2px 0 0', color: 'var(--text-primary)' }}>{c.body}</p>
          </div>
        ))}
      </div>

      {mentionQuery !== null && (
        <div
          style={{
            background: 'var(--surface-2)',
            border: '1px solid var(--border-subtle)',
            borderRadius: 4,
            padding: '4px 0',
            fontSize: 12,
          }}
        >
          <div style={{ padding: '4px 8px', color: 'var(--text-muted)' }}>
            @mention — workspace member picker (WP-030)
          </div>
        </div>
      )}

      {!isResolved && (
        <textarea
          ref={inputRef}
          value={body}
          onChange={handleBodyChange}
          onKeyDown={handleKeyDown}
          placeholder="Reply… (Enter to send, Cmd+Enter to resolve)"
          rows={2}
          style={{
            resize: 'none',
            fontSize: 13,
            padding: '6px 8px',
            border: '1px solid var(--border-subtle)',
            borderRadius: 4,
            background: 'var(--surface-2)',
            color: 'var(--text-primary)',
            fontFamily: 'inherit',
          }}
        />
      )}
    </div>
  );
}

