              }}
            >
              Resolve
            </button>
          )}
          <button
            onClick={onClose}
            style={{
              fontSize: 14,
              lineHeight: 1,
              border: 'none',
              background: 'none',
              cursor: 'pointer',
              color: 'var(--text-muted)',
            }}
            aria-label="Close"
          >
            ×
          </button>
        </div>
      </div>

      <div
        style={{ overflowY: 'auto', flex: 1, display: 'flex', flexDirection: 'column', gap: 8 }}
      >
        {comments.map((c) => (
          <div key={c.id} style={{ fontSize: 13 }}>
