    @app.get("/api/models/{model_id}/comments")
    async def list_comments(model_id: str, threadId: str | None = None) -> Any:
        cs = _comments(model_id)
        return {"comments": [c for c in cs if c.get("threadId") == threadId] if threadId else cs}
    @app.patch("/api/models/{model_id}/comments/{cid}/resolve")
    async def resolve_comment(model_id: str, cid: str) -> Any:
        for i, c in enumerate(_comments(model_id)):
