import { create } from 'zustand';

import type { Comment } from '@bim-ai/core';

type CommentStore = {
  comments: Comment[];
  modelId: string | null;
  load: (modelId: string) => Promise<void>;
  addComment: (
    modelId: string,
    payload: Omit<Comment, 'id' | 'modelId' | 'createdAt' | 'isOrphaned'>,
  ) => Promise<Comment>;
  resolveComment: (modelId: string, commentId: string) => Promise<void>;
  deleteComment: (modelId: string, commentId: string) => Promise<void>;
};

export const useCommentStore = create<CommentStore>((set) => ({
  comments: [],
  modelId: null,

  async load(modelId) {
    const res = await fetch(`/api/models/${modelId}/comments`);
    if (!res.ok) return;
    const data = (await res.json()) as { comments: Comment[] };
    set({ comments: data.comments, modelId });
  },

  async addComment(modelId, payload) {
    const res = await fetch(`/api/models/${modelId}/comments`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        authorId: payload.authorId,
        body: payload.body,
        anchor: payload.anchor,
        threadId: payload.threadId,
      }),
    });
    if (!res.ok) throw new Error('Failed to create comment');
    const comment = (await res.json()) as Comment;
    set((s) => ({ comments: [...s.comments, comment] }));
    return comment;
  },

  async resolveComment(modelId, commentId) {
    const res = await fetch(`/api/models/${modelId}/comments/${commentId}/resolve`, {
      method: 'PATCH',
    });
    if (!res.ok) throw new Error('Failed to resolve comment');
    const updated = (await res.json()) as Comment;
    set((s) => ({
      comments: s.comments.map((c) => (c.id === commentId ? updated : c)),
    }));
  },

  async deleteComment(modelId, commentId) {
    const res = await fetch(`/api/models/${modelId}/comments/${commentId}`, {
      method: 'DELETE',
    });
    if (!res.ok) throw new Error('Failed to delete comment');
    set((s) => ({ comments: s.comments.filter((c) => c.id !== commentId) }));
  },
}));
