_comment_store: dict[str, list[dict]] = {}


def _model_comments(model_id: str) -> list[dict]:
    return _comment_store.setdefault(str(model_id), [])


class CreateCommentBody(BaseModel):
    model_config = ConfigDict(populate_by_name=True, extra="ignore")
    thread_id: str | None = Field(default=None, alias="threadId")
    author_id: str = Field(alias="authorId")
    body: str
    anchor: dict


@api_router.post("/models/{model_id}/comments")
async def create_comment(model_id: UUID, body: CreateCommentBody) -> dict[str, Any]:
    import time
    from bim_ai.comments import Comment
    cid = str(uuid4()); tid = body.thread_id if body.thread_id else cid
    raw: dict[str, Any] = {"id": cid, "modelId": str(model_id), "threadId": tid, "authorId": body.author_id, "body": body.body, "anchor": body.anchor, "createdAt": int(time.time() * 1000), "isOrphaned": False}
    comment = Comment.model_validate(raw)
    _model_comments(str(model_id)).append(comment.model_dump(by_alias=True))
    return comment.model_dump(by_alias=True)


@api_router.get("/models/{model_id}/comments")
async def list_comments(model_id: UUID, thread_id: Annotated[str | None, Query(alias="threadId")] = None) -> dict[str, Any]:
    comments = _model_comments(str(model_id))
    if thread_id is not None:
        comments = [c for c in comments if c.get("threadId") == thread_id]
    return {"comments": comments}


@api_router.patch("/models/{model_id}/comments/{comment_id}/resolve")
async def resolve_comment(model_id: UUID, comment_id: str) -> dict[str, Any]:
    import time
    comments = _model_comments(str(model_id))
    for i, c in enumerate(comments):
        if c.get("id") == comment_id:
            c = dict(c); c["resolvedAt"] = int(time.time() * 1000); comments[i] = c; return c
    raise HTTPException(status_code=404, detail="Comment not found")


@api_router.delete("/models/{model_id}/comments/{comment_id}")
async def delete_comment(model_id: UUID, comment_id: str) -> dict[str, Any]:
    comments = _model_comments(str(model_id))
    for i, c in enumerate(comments):
        if c.get("id") == comment_id:
            comments.pop(i); return {"deleted": True, "id": comment_id}
    raise HTTPException(status_code=404, detail="Comment not found")



